files.content:
body {
  margin: 0;
  font-family: 'Segoe UI', sans-serif;
  background: #f4f7fb;
  color: #152230;
}

main {
  width: min(860px, 92vw);
  margin: 2rem auto;
  padding: 1.2rem;
  border-radius: 0.9rem;
  background: #ffffff;
  box-shadow: 0 12px 30px rgba(11, 31, 50, 0.08);
}

.symbol-grid {
  display: grid;
  grid-template-columns: repeat(7, minmax(0, 1fr));
  gap: 0.45rem;
}

.symbol-grid button {
  border: 0;
  border-radius: 0.5rem;
  padding: 0.45rem;
  background: #11263a;
  color: #f7fbff;
  font-size: 1.05rem;
  font-weight: 700;
  cursor: pointer;
}

.symbol-grid button.is-active {
  background: #f3ad3b;
  color: #191200;
}

.detail {
  margin-top: 1rem;
  padding: 0.8rem;
  border-radius: 0.7rem;
  background: #eff4fb;
}

const map = [
  { symbol: '<', key: '<>-tast', shift: false, altgr: false },
  { symbol: '>', key: '<>-tast', shift: true, altgr: false },
  { symbol: '|', key: 'AltGr + ´', shift: false, altgr: true },
  { symbol: '?', key: 'Shift + +', shift: true, altgr: false },
  { symbol: '!', key: 'Shift + 1', shift: true, altgr: false },
  { symbol: '"', key: 'Shift + 2', shift: true, altgr: false },
  { symbol: ':', key: 'Shift + .', shift: true, altgr: false },
  { symbol: ';', key: 'Shift + ,', shift: true, altgr: false },
  { symbol: '%', key: 'Shift + 5', shift: true, altgr: false },
  { symbol: '&', key: 'Shift + 6', shift: true, altgr: false },
  { symbol: '/', key: 'Shift + 7', shift: true, altgr: false },
  { symbol: '(', key: 'Shift + 8', shift: true, altgr: false },
  { symbol: ')', key: 'Shift + 9', shift: true, altgr: false },
  { symbol: '[', key: 'AltGr + 8', shift: false, altgr: true },
  { symbol: ']', key: 'AltGr + 9', shift: false, altgr: true },
  { symbol: '{', key: 'AltGr + 7', shift: false, altgr: true },
  { symbol: '}', key: 'AltGr + 0', shift: false, altgr: true },
  { symbol: '#', key: 'Shift + 3', shift: true, altgr: false },
  { symbol: '-', key: '-tast', shift: false, altgr: false },
  { symbol: '_', key: 'Shift + -', shift: true, altgr: false },
  { symbol: '*', key: 'Shift + apostrof', shift: true, altgr: false }
];

const grid = document.getElementById('symbol-grid');
const outSymbol = document.getElementById('out-symbol');
const outKey = document.getElementById('out-key');
const outShift = document.getElementById('out-shift');
const outAltgr = document.getElementById('out-altgr');

function show(entry, btn) {
  if (!outSymbol || !outKey || !outShift || !outAltgr) return;

  outSymbol.textContent = entry.symbol;
  outKey.textContent = entry.key;
  outShift.textContent = entry.shift ? 'Ja' : 'Nej';
  outAltgr.textContent = entry.altgr ? 'Ja' : 'Nej';

  document.querySelectorAll('.symbol-grid button').forEach((button) => {
    button.classList.remove('is-active');
  });
  btn.classList.add('is-active');
}

for (const entry of map) {
  const button = document.createElement('button');
  button.type = 'button';
  button.textContent = entry.symbol;
  button.addEventListener('click', () => show(entry, button));
  grid?.append(button);
}

const firstButton = document.querySelector('.symbol-grid button');
if (map[0] && firstButton instanceof HTMLButtonElement) {
  show(map[0], firstButton);
}
